import "./Article.css";

export default function JPArticle() {
  return (
    <main className="article-page">
      <article className="article-container">

        <h1 className="article-title">J vs P</h1>

        <img
          src="/jvsp.png"
          alt="Judging vs Perceiving"
          className="article-hero"
        />

        <p className="lead">
          Judging (J) და Perceiving (P) აღწერს იმას&#44; როგორ უდგება ადამიანი ცხოვრებასა და ყოველდღიურ საქმეებს &#8210; ურჩევნია წინასწარ დაგეგმილი სტრუქტურა თუ მოქნილი&#44; სპონტანური მიდგომა&#46; ეს განზომილება არ ეხება განსჯას ან ქაოსს&#44; იგი ასახავს ცხოვრების ორგანიზების ფსიქოლოგიურ სტილს&#46;
        </p>

        <h3>იუნგის თეორიული საფუძველი</h3>
        <p>
          კარლ იუნგის თეორიაში ეს განსხვავება უკავშირდება იმას&#44; როგორ გამოხატავს ადამიანი გარე სამყაროში საკუთარ ძირითად ფუნქციებს&#46; მოგვიანებით&#44; MBTI-ის ავტორებმა (ბრიგზი და მაიერსი) ეს იდეა ჩამოაყალიბეს როგორც Judging და Perceiving მიდგომები&#46;
          <strong>Judging (J)</strong> ტიპები უპირატესობას ანიჭებენ წესრიგს&#44; დაგეგმვასა და დასრულებულობას&#46;
          <strong>Perceiving (P)</strong> ტიპები კი ღიად ტოვებენ ვარიანტებს&#44; ადვილად ეგუებიან ცვლილებებს და პროცესს შედეგზე წინ აყენებენ&#46;
        </p>

        <h3>თანამედროვე ფსიქოლოგიური ხედვა</h3>
        <p>
          თანამედროვე ფსიქოლოგიაში ეს განსხვავება ხშირად აიხსნება როგორც თვითრეგულაციისა და დროის მართვის სტილი&#46;
          <strong>J ტიპები</strong> თავს კომფორტულად გრძნობენ მაშინ&#44; როცა არსებობს მკაფიო გეგმა&#44; ვადები და სტრუქტურა&#46; მათთვის გადაწყვეტილების მიღება ამცირებს გაურკვევლობას&#46;
          <strong>P ტიპები</strong> უფრო ეფექტურად მუშაობენ ღია გარემოში&#44; სადაც შეუძლიათ ადაპტაცია და სიტუაციის მიხედვით მოქმედება&#46; მათთვის მოქნილობა ზრდის კრეატიულობასა და მოტივაციას&#46;
          კვლევები აჩვენებს&#44; რომ ეს განსხვავება მნიშვნელოვან როლს თამაშობს სამუშაო სტილში&#44;სტრესის მართვასა და ყოველდღიური რუტინის ორგანიზებაში&#46;
        </p>

        <h3>გავრცელებული მცდარი წარმოდგენები</h3>
        <ul>
          <li>Judging ნიშნავს მკაცრობას ან ზედმეტ კონტროლს</li>
          <li>Perceiving ნიშნავს მოუწესრიგებლობას ან უპასუხისმგებლობას</li>
        </ul>

        <p>
          რეალურად&#44; ორივე სტილი ეფექტურია განსხვავებულ კონტექსტებში &#8210; ერთი უზრუნველყოფს სტაბილურობას&#44; მეორე კი მოქნილობას&#46;
          J და P წარმოადგენს ცხოვრების ორგანიზების განსხვავებულ მიდგომას&#44; და არა უკეთეს ან უარეს თვისებას&#46; ფსიქოლოგიური კეთილდღეობა ხშირად დამოკიდებულია იმაზე&#44; რამდენად შეესაბამება ადამიანის ცხოვრების სტილი მის ბუნებრივ მიდრეკილებებს&#46;
          ამ განსხვავების გაცნობიერება ეხმარება ადამიანს უკეთ მართოს დრო&#44; სტრესი და ურთიერთობები&#46;
        </p>

        <h3>წყაროები</h3>
        <ul className="sources">
          <li>Carl Jung (1921)  <em>Psychological Types</em></li>
          <li>Myers, I. B., & Myers, P. B. (1995)  <em>Gifts Differing</em></li>
          <li>APA Dictionary of Psychology  Self-regulation & personality</li>
          <li>McCrae, R. R., & Costa (1999)  A Five-Factor Theory of Personality</li>
          <li>Keirsey, D. (1998)  <em>Please Understand Me I</em></li>
        </ul>

      </article>
    </main>
  );
}
